agent-browser eval "
(async () => {
  const data = await fetch('https://cdn.jsdelivr.net/npm/vega-datasets@v1.29.0/data/iowa-electricity.csv').then(r => r.text());
  const rows = data.split('\n').slice(1).map(line => {
    const [year, source, net_generation] = line.split(',');
    return { year: new Date(year).getFullYear(), net_generation: parseFloat(net_generation) };
  }).filter(r => !isNaN(r.net_generation));

  const medians = {};
  rows.forEach(r => {
    if (!medians[r.year]) medians[r.year] = [];
    medians[r.year].push(r.net_generation);
  });

  const results = Object.keys(medians).map(year => {
    const vals = medians[year].sort((a, b) => a - b);
    const mid = Math.floor(vals.length / 2);
    const median = vals.length % 2 !== 0 ? vals[mid] : (vals[mid - 1] + vals[mid]) / 2;
    return { year, median };
  });

  results.sort((a, b) => b.median - a.median);
  return results[0];
})()
"

