(async () => {
  const spec = {
    'data': {'url': 'https://cdn.jsdelivr.net/npm/vega-datasets@v1.29.0/data/iowa-electricity.csv'},
    'transform': [
      {
        'aggregate': [
          {
            'op': 'median',
            'field': 'net_generation',
            'as': 'median_gen'
          }
        ],
        'groupby': [
          'year(year)'
        ]
      }
    ]
  };
  const res = await vegaEmbed(document.createElement('div'), spec);
  // In Vega-Lite, the transformed data is often in a dataset named 'data_0', 'data_1', etc.
  // Or we can check the names.
  const dataNames = Object.keys(res.view._runtime.data);
  const dataResults = {};
  for (const name of dataNames) {
    const d = res.view.data(name);
    if (d && d.length > 0 && d[0].median_gen !== undefined) {
      dataResults[name] = d[0];
    }
  }
  return dataResults;
})()
"

